/* Apply to body or specific text elements for global effect */
body {
  -webkit-font-smoothing: antialiased; /* For macOS & iOS with WebKit */
  -moz-osx-font-smoothing: grayscale; /* For Firefox on macOS */
  text-rendering: optimizeLegibility; /* Enables ligatures, kerning, better hinting */
}

/* Example for specific, performance-sensitive elements if optimizeLegibility causes issues */
h1, .hero-title {
  text-rendering: optimizeSpeed; /* Prioritizes rendering speed over advanced features */
}
